mapper.select:
select max(STRATEGY_YIELD) maxStrategyYield, max(INDEX_YIELD) maxIndexYield, min(STRATEGY_YIELD) minStrategyYield, min(INDEX_YIELD) minIndexYield from ( WITH STRATEGY_INDEX_NAV AS ( SELECT A.ST_DATE SK_DATE, B.SK_STRATEGY, C.MKT_ISSUE_SHORT_NAME INDEX_NAME, B.STRATEGY_NAME, NVL(A.YEILD,0) STRATEGY_YIELD, decode(A.YEILD,null,0,c.YIELD) INDEX_YIELD FROM app_pms.ST_STRATEGYNAV_DAILY A INNER JOIN app_pms.TSTRATEGY_MARKET_INFO B ON A.PMS_ID = B.SK_STRATEGY LEFT JOIN app_pms.ST_ISSU_INDEX_QUOTATION C ON A.ST_DATE = C.SK_DATE AND B.INDEX_NAME = C.MKT_ISSUE_SHORT_NAME WHERE B.SK_STRATEGY = #{skStrategy}
AND A.ST_DATE >= #{startDate}
AND A.ST_DATE <= #{endDate}
and to_char(sysdate,'yyyyMMdd') > a.st_date ), YIELD_DAY AS ( SELECT A.SK_DATE, A.SK_STRATEGY, A.INDEX_NAME, A.STRATEGY_NAME, to_char(to_date(A.SK_DATE,'yyyyMMdd'),'yyyy') C_YEAR, to_char(to_date(A.SK_DATE,'yyyyMMdd'),'yyyyMM') C_MONTH, to_char(to_date(A.SK_DATE,'yyyyMMdd'),'ww') C_WEEK, A.STRATEGY_YIELD, A.INDEX_YIELD FROM STRATEGY_INDEX_NAV A ORDER BY A.SK_DATE ), YIELD_WEEK_MONTH AS ( SELECT A.SK_DATE, A.SK_STRATEGY, A.INDEX_NAME, A.STRATEGY_NAME, RANK() OVER(PARTITION BY A.C_MONTH ORDER BY A.SK_DATE DESC) MONTH_RANK_NUM, RANK() OVER(PARTITION BY A.C_YEAR, A.C_WEEK ORDER BY A.SK_DATE DESC) WEEK_RANK_NUM,
EXP(SUM(LN(1 + A.STRATEGY_YIELD)) OVER (PARTITION BY A.C_YEAR, A.C_WEEK ORDER BY A.SK_DATE)) - 1 STRATEGY_YIELD_W, EXP(SUM(LN(1 + A.INDEX_YIELD)) OVER (PARTITION BY A.C_YEAR, A.C_WEEK ORDER BY A.SK_DATE)) - 1 INDEX_YIELD_W,
EXP(SUM(LN(1 + A.STRATEGY_YIELD)) OVER (PARTITION BY A.C_MONTH ORDER BY A.SK_DATE)) - 1 STRATEGY_YIELD_M, EXP(SUM(LN(1 + A.INDEX_YIELD)) OVER (PARTITION BY A.C_MONTH ORDER BY A.SK_DATE)) - 1 INDEX_YIELD_M,
EXP(SUM(LN(1 + A.STRATEGY_YIELD)) OVER (ORDER BY A.SK_DATE)) - 1 STRATEGY_YIELD_D, EXP(SUM(LN(1 + A.INDEX_YIELD)) OVER (ORDER BY A.SK_DATE)) - 1 INDEX_YIELD_D FROM YIELD_DAY A ORDER BY A.SK_DATE ) SELECT A.SK_DATE, A.SK_STRATEGY, A.INDEX_NAME, A.STRATEGY_NAME, CASE WHEN #{timeDimension} = 'W' THEN A.STRATEGY_YIELD_W WHEN #{timeDimension} = 'M' THEN STRATEGY_YIELD_M ELSE A.STRATEGY_YIELD_D END STRATEGY_YIELD,
CASE WHEN #{timeDimension} = 'W' THEN A.INDEX_YIELD_W WHEN #{timeDimension} = 'M' THEN INDEX_YIELD_M ELSE A.INDEX_YIELD_D END INDEX_YIELD FROM YIELD_WEEK_MONTH A
AND A.WEEK_RANK_NUM = 1
AND A.MONTH_RANK_NUM = 1
)
